options.afterRender:
import("/esm/datatables.net-bs5").then(({ default: DataTable }) => {
  $(document).ready(function () {
    const HOST = "/cpms";
    let table;
    let isEdit = false;

    const GROUP = "Scheduling";
    const grouping = JSON.parse(context.grafana.replaceVariables("$grouping"));
    const allowedKeys = grouping[GROUP] ? Object.keys(grouping[GROUP]) : [];
    const rawData = context.data;
    const data = Array.isArray(rawData)
      ? rawData.filter(item => item && item.key && allowedKeys.includes(item.key))
      : [];

    const isBooleanParam = (row) => row.key === "schedule.enabled";
    const isEnabled = (value) => value === true || value === "true";

    table = new DataTable("#ptp-table-1", {
      retrieve: true,
      searching: false,
      paging: false,
      pageLength: 10,
      lengthChange: false,
      ordering: true,
      info: false,
      data: data ?? [],
      order: [[0, "asc"]],
      columns: [
        {
          data: null,
          className: "col-setting",
          render: function (_, __, row) {
            return '<div class="ptp-label">' + (grouping[GROUP][row.key] ?? '-') + '</div>' +
              '<div class="ptp-hint">' + (row.description ?? '') + '</div>';
          }
        },
        {
          data: "value",
          className: "col-value ptp-value",
          render: function (value, _, row) {
            if (row.isEditingRow && isBooleanParam(row)) {
              const selected = isEnabled(value) ? "true" : "false";
              return '<div class="ptp-edit-row">' +
                '<select class="ptp-input ptp-boolean-field">' +
                '<option value="true" ' + (selected === "true" ? "selected" : "") + '>Enabled</option>' +
                '<option value="false" ' + (selected === "false" ? "selected" : "") + '>Disabled</option>' +
                '</select>' +
                '<span class="ptp-unit">' + (row.unit ?? '') + '</span>' +
                '</div>';
            }

            if (row.isEditingRow) {
              const timeParts = String(value || "00:00:00").split(":");
              const hours = timeParts[0] || "00";
              const minutes = timeParts[1] || "00";
              const seconds = timeParts[2] || "00";

              return '<div class="ptp-edit-row time-picker-group">' +
                '<input class="ptp-input ptp-time-field hh" type="number" min="0" max="23" placeholder="HH" style="width: 50px; text-align: center;" value="' + hours + '">' +
                '<span>:</span>' +
                '<input class="ptp-input ptp-time-field mm" type="number" min="0" max="59" placeholder="MM" style="width: 50px; text-align: center;" value="' + minutes + '">' +
                '<span>:</span>' +
                '<input class="ptp-input ptp-time-field ss" type="number" min="0" max="59" placeholder="SS" style="width: 50px; text-align: center;" value="' + seconds + '">' +
                '<span class="ptp-unit">' + (row.unit ?? '') + '</span>' +
                '</div>';
            }

            if (isBooleanParam(row)) return isEnabled(value) ? "Enabled" : "Disabled";
            return String(value ?? "-") + ' <span class="ptp-unit">' + (row.unit ?? '') + '</span>';
          }
        },
        {
          data: null,
          className: "col-action dt-body-center",
          render: function (_, __, row) {
            if (row.isLoading) return '<i class="fa fa-spinner fa-spin"></i>';
            if (row.isEditingRow) {
              return '<div class="ptp-actions">' +
                '<button class="ptp-btn ptp-btn-icon ptp-btn-save saveSetting btn-secondary" type="button" title="Save" aria-label="Save"><i class="fa fa-check" aria-hidden="true"></i></button>' +
                '<button class="ptp-btn ptp-btn-icon ptp-btn-cancel cancelSetting btn-secondary" type="button" title="Cancel" aria-label="Cancel"><i class="fa fa-times" aria-hidden="true"></i></button>' +
                '</div>';
            }
            return '<button class="ptp-btn ptp-btn-icon editSetting btn-secondary" type="button" title="Edit" aria-label="Edit" ' + (row.isDisableEdit ? "disabled" : "") + '><i class="fa fa-pencil" aria-hidden="true"></i></button>';
          }
        }
      ]
    });

    table.clear().rows.add(data).draw(false);
    resetEvents();

    function post(url, data) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'post',
          contentType: 'application/json',
          data: JSON.stringify(data),
          processData: false,
          success: function (response) { resolve(response); },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function resetEvents() {
      const tableEl = $("#ptp-table-1");
      tableEl.off();

      tableEl.on("click", "button.editSetting", function () {
        const row = table.row($(this).closest("tr"));
        const data = row.data();
        if (isEdit) return alert("Can only edit one record at a time");
        isEdit = true;
        data.isEditingRow = true;
        row.invalidate().draw(false);
      });

      tableEl.on("click", "button.saveSetting", async function () {
        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();
        const reason = prompt("Remark for this change:", "");
        if (reason === null) return;
        data.isLoading = true;

        const handleValidationError = (message) => {
          alert(message);
          data.isLoading = false;
          row.invalidate().draw(false);
        };

        let value;

        if (isBooleanParam(data)) {
          value = tr.find('.ptp-boolean-field').val() === 'true';
        } else {
          const hhRaw = String(tr.find('.ptp-time-field.hh').val() ?? '');
          const mmRaw = String(tr.find('.ptp-time-field.mm').val() ?? '');
          const ssRaw = String(tr.find('.ptp-time-field.ss').val() ?? '');

          if (hhRaw.includes('.') || mmRaw.includes('.') || ssRaw.includes('.')) {
            handleValidationError("Please enter whole numbers only. Decimals/floats are not allowed.");
            return;
          }

          const hhVal = parseInt(hhRaw, 10);
          const mmVal = parseInt(mmRaw, 10);
          const ssVal = parseInt(ssRaw, 10);

          if (Number.isNaN(hhVal) || Number.isNaN(mmVal) || Number.isNaN(ssVal)) {
            handleValidationError("Please enter a valid number for hours, minutes, and seconds.");
            return;
          }

          if (hhVal < 0 || hhVal > 23 || mmVal < 0 || mmVal > 59 || ssVal < 0 || ssVal > 59) {
            handleValidationError("Please enter a valid time range (Hours between 0 and 23 || Minutes/Seconds between 0 and 59).");
            return;
          }

          value = String(hhVal).padStart(2, '0') + ':' + String(mmVal).padStart(2, '0') + ':' + String(ssVal).padStart(2, '0');
        }

        const payload = {
          scope: data.scope,
          equipmentKind: data.equipment_kind,
          equipmentId: data.equipment_id,
          key: data.key,
          value,
          reason: reason.trim() || null,
        };

        row.invalidate().draw(false);

        try {
          if (data.value !== payload.value) await post(HOST + '/params/value', payload);
          Object.assign(data, { value: payload.value, isEditingRow: false, isLoading: false });
          isEdit = false;
          row.invalidate().draw(false);
          context.grafana.refresh();
          setTimeout(() => alert("Updated!"), 100);
        } catch (e) {
          data.isLoading = false;
          row.invalidate().draw(false);
          alert('Error: ' + (e.response ?? e.message));
          console.error(e);
        }
      });

      tableEl.on("click", "button.cancelSetting", function () {
        const row = table.row($(this).closest("tr"));
        const data = row.data();
        data.isEditingRow = false;
        isEdit = false;
        row.invalidate().draw(false);
      });
    }
  })
});

