  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
}

.ptp-actions { display: flex; gap: 8px; }

.ptp-btn {
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
  font-weight: 400 !important;
  padding: 7px 16px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
}
// .ptp-btn:hover { background: #f4f4f2; border-color: #bcbcb4; }

.ptp-btn-save {
  font-weight: 400;
  padding: 7px 14px;
}
// .ptp-btn-save:hover { background: #000; }

.ptp-btn-cancel {
  font-size: 18px;
  line-height: 1;
  padding: 7px 14px;
}

.ptp-note {
  margin-top: 14px;
  font-size: 12.5px;
  font-family: Inter, Helvetica, Arial, sans-serif;
}

.ptp-btn-icon {
  width: 34px;
  height: 34px;
  padding: 0;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.ptp-btn-icon .fa {
  font-size: 14px;
  line-height: 1;
}

