import("/esm/datatables.net-bs5").then(({ default: DataTable }) => {
  $(document).ready(function () {
    const HOST = "/cpms";
    let table;
    let isEdit = false;

    const GROUP = "Plant Warmup";
    const grouping = JSON.parse(context.grafana.replaceVariables("$grouping"));

    let rawData = context.data;

    const allowedKeys = grouping[GROUP] ? Object.keys(grouping[GROUP]) : [];

    const data = Array.isArray(rawData)
      ? rawData.filter(item => item && item.key && allowedKeys.includes(item.key))
      : [];

    const isMsParam = (row) => row && row.unit === "ms";
    const formatUnit = (row) => isMsParam(row) ? "s" : (row.unit ?? "");
    const formatValue = (value, row) => {
      if (!isMsParam(row) || value === null || value === undefined || value === "") return value;
      const seconds = Number(value) / 1000;
      return Number.isInteger(seconds) ? seconds : Number(seconds.toFixed(3));
    };
    const toPayloadValue = (value, row) => isMsParam(row) ? Math.round(value * 1000) : value;


    table = new DataTable("#ptp-table-2", {
      retrieve: true,
      searching: false,
      paging: false,
      pageLength: 10,
      lengthChange: false,
      ordering: true,
      info: false,
      data: data ?? [],
      order: [
        [0, "asc"],
        [1, "asc"],
        [2, "desc"],
      ],
      columns: [
        {
          data: null,
          className: "col-setting",
          render: function (data, type, row) {
            return `
        <div class="ptp-label">${grouping[GROUP][row.key] ?? "-"}</div>
        <div class="ptp-hint">${row.description ?? ""}</div>
      `;
          }
        },
        {
          data: "value",
          className: "col-value ptp-value",
          render: function (data, type, row) {
            if (row.isEditingRow) {
              return `
          <div class="ptp-edit-row">
            <input id="newValue2" class="ptp-input" placeholder="Enter Numerical Value" type="number" value="${formatValue(data, row) ?? ''}">
            <span class="ptp-unit">${formatUnit(row)}</span>
          </div>
        `;
            }
            return `${formatValue(data, row) ?? "-"} <span class="ptp-unit">${formatUnit(row)}</span>`;
          }
        },
        {
          data: null,
          className: "col-action dt-body-center",
          render: function (_, __, row) {
            if (row.isLoading) {
              return `<i class="fa fa-spinner fa-spin"></i>`;
            }
            if (row.isEditingRow) {
              return `
          <div class="ptp-actions">
            <button class="ptp-btn ptp-btn-icon ptp-btn-save saveSetting btn-secondary" type="button" title="Save" aria-label="Save"><i class="fa fa-check" aria-hidden="true"></i></button>
            <button class="ptp-btn ptp-btn-icon ptp-btn-cancel cancelSetting btn-secondary" type="button" title="Cancel" aria-label="Cancel"><i class="fa fa-times" aria-hidden="true"></i></button>
          </div>
        `;
            }
            return `
        <button class="ptp-btn ptp-btn-icon editSetting btn-secondary" type="button" title="Edit" aria-label="Edit" ${row.isDisableEdit ? "disabled" : ""}><i class="fa fa-pencil" aria-hidden="true"></i></button>
      `;
          }
        }
      ]
    });

    table.clear().rows.add(data).draw(false);
    resetEvents();

    function patch(url, data) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'post',
          contentType: 'application/json',
          data: JSON.stringify(data),
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function put(url, data) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'put',
          contentType: 'application/json',
          data: JSON.stringify(data),
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function get(url) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'get',
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function del(url) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'post',
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function resetEvents() {
      const tableEl = $("#ptp-table-2");
      tableEl.off();

      tableEl.on("click", "button.editSetting", function () {
        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();

        if (isEdit) return alert("Can only edit one record at a time");

        isEdit = true;
        data.isEditingRow = true;
        row.invalidate().draw(false);
      });

      tableEl.on("click", "button.saveSetting", async function () {
        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();
        const reason = prompt("Remark for this change:", "");
        if (reason === null) return;
        data.isLoading = true;

        const handleValidationError = (message) => {
          alert(message);
          data.isLoading = false;
        };

        const rawValue = $(".ptp-input").val();

        const value = parseFloat(rawValue, 10)

        if (isNaN(value)) {
          handleValidationError("Please enter a valid number.");
          return;
        }

        if (value < 0) {
          handleValidationError("Please enter a number more than 0.");
          return;
        }

        const payload = {
          scope: data.scope,
          equipmentKind: data.equipment_kind,
          equipmentId: data.equipment_id,
          key: data.key,
          value: toPayloadValue(value, data),
          reason: reason.trim() || null,
        };

        try {
          if (data.value !== payload.value) {
            await patch(`${HOST}/params/value`, payload);
          }
          Object.assign(data, {
            isEditingRow: false,
            isLoading: false,
          });

          isEdit = false;
          context.grafana.refresh();
          setTimeout(() => {
            alert("Updated!");
          }, 100);
        } catch (e) {
          alert(`Error: ${e.response ? e.response.data.message : e.message}`);
          console.error(e);
        }
      });

      tableEl.on("click", "button.cancelSetting", function () {
        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();
        data.isEditingRow = false;
        isEdit = false;
        row.invalidate().draw(false);
      });
    }
  })
});

