          type: 'put',
          contentType: 'application/json',
          data: JSON.stringify(data),
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function get(url) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'get',
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

    function del(url) {
      return new Promise((resolve, reject) => {
        $.ajax({
          url,
          dataType: 'json',
          type: 'post',
          processData: false,
          success: function (response, textStatus, jQxhr) {
            resolve(response);
          },
          error: function (jqXhr, textStatus, errorThrown) {
            reject({ response: jqXhr.responseText, error: errorThrown });
          },
        });
      });
    }

