        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();
        const reason = prompt("Remark for this change:", "");
        if (reason === null) return;
        data.isLoading = true;

        const handleValidationError = (message) => {
          alert(message);
          data.isLoading = false;
        };

        const rawValue = $(".ptp-input").val();

        const value = parseFloat(rawValue, 10)

        if (isNaN(value)) {
          handleValidationError("Please enter a valid number.");
          return;
        }

        if (value < 0) {
          handleValidationError("Please enter a number more than 0.");
          return;
        }

        // Compile payload using the updated layout properties
        const payload = {
          scope: data.scope,
          equipmentKind: data.equipment_kind,
          equipmentId: data.equipment_id,
          key: data.key,
          value: toPayloadValue(value, data),
          reason: reason.trim() || null,
        };

        try {
          if (data.value !== payload.value) {
            await patch(`${HOST}/params/value`, payload);
          }
          Object.assign(data, {
            isEditingRow: false,
            isLoading: false,
          });

          isEdit = false;
          context.grafana.refresh();
          setTimeout(() => {
            alert("Updated!");
          }, 100);
        } catch (e) {
          alert(`Error: ${e.response ? e.response.data.message : e.message}`);
          console.error(e);
        }


      });

      tableEl.on("click", "button.cancelSetting", function () {
        const tr = $(this).closest("tr");
        const row = table.row(tr);
        const data = row.data();
        data.isEditingRow = false;
        isEdit = false;
        row.invalidate().draw(false);
      });

    }
  })
});

