.ptp-actions { 
  display: flex; 
  gap: 8px; 
  justify-content: center; 
  align-items: center; 
}

div.dt-container div.dt-layout-row div.dt-layout-cell.dt-layout-end {
  margin-left: 0;
} 

.ptp-wrap { width: 100%; max-width: 880px; }

.ptp-head { margin-bottom: 24px; }
.ptp-eyebrow {
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 12px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  margin-bottom: 6px;
}
.ptp-title {
  margin: 0;
  font-size: 26px;
  font-weight: 600;
  letter-spacing: -0.01em;
}

