  height: 48px;
  padding: 0 24px;
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
  font-weight: 500;
}

.ptp-table .col-setting { width: auto; }
.ptp-table .col-value { width: 38%; }
.ptp-table .col-action { width: 132px; }

.ptp-table td {
  padding: 14px 24px;
  vertical-align: middle;
}
.ptp-table tr:last-child td { border-bottom: none; }

.ptp-label { font-size: 15px; font-weight: 500; }
.ptp-hint { font-size: 12.5px; color: #9a9a92; margin-top: 2px; }

.ptp-value {
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
}

.ptp-edit-row { display: flex; align-items: center; gap: 8px; }

