  flex: 1;
  min-width: 0;
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
  padding: 9px 11px;
  border: 1.5px solid #1c1c1a;
  border-radius: 6px;
  outline: none;
}

.ptp-unit {
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
}

.ptp-actions { display: flex; gap: 8px; }

.ptp-btn {
  font-family: Inter, Helvetica, Arial, sans-serif;
  font-size: 14px;
  font-weight: 400 !important;
  padding: 7px 16px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
}
