.ptp-btn-save {
  font-weight: 400;
  padding: 7px 14px;
}
// .ptp-btn-save:hover { background: #000; }

.ptp-btn-cancel {
  font-size: 18px;
  line-height: 1;
  padding: 7px 14px;
}

.ptp-note {
  margin-top: 14px;
  font-size: 12.5px;
  font-family: Inter, Helvetica, Arial, sans-serif;
}

.ptp-btn-icon {
  width: 34px;
  height: 34px;
  padding: 0;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.ptp-btn-icon .fa {
  font-size: 14px;
  line-height: 1;
